UPDATE transactions SET category = NULL, category_id = NULL, type = 'egreso', has_iva = false, has_retefuente = false, has_reteica = false, iva_amount = 0, retefuente_amount = 0, reteica_amount = 0 WHERE deleted_at IS NULL AND amount <= 0 AND category = 'ventas' AND (description ILIKE '%TRANSFERENCIA CTA SUC VIRTUAL%' OR description ILIKE '%CONSIG NACIONAL EFECTIVO%' OR description ILIKE '%CONSIGNACION LOCAL CAJ%' OR description ILIKE '%CONSIGNACION CORRESPONSAL%')